      {
        "name": "1-3条消息但超过30天未联系",
        "all": [
          {"field": "realMsgs", "op": "gte", "value": 1},
          {"field": "realMsgs", "op": "lte", "value": 3},
          {"field": "daysAgo", "op": "gte", "value": 30}
        ]
      },
      {
        "name": "30-60天未联系但曾有互动",
        "all": [
          {"field": "daysAgo", "op": "gte", "value": 30},
          {"field": "daysAgo", "op": "lt", "value": 60},
          {"field": "realMsgs", "op": "gte", "value": 4},
          {"field": "realMsgs", "op": "lt", "value": 10}
        ]
      }
    ]
  },

  "p4": {
    "label": "沉默/沉睡",
    "description": "超过60天未联系或几乎无对话",
    "default": true
